// MailerLite envía eventos en batch cuando batchable: true
// Estructura: { account_id, type, total, events: [...] }
const body = $input.first().json.body || $input.first().json;

// Soporta batch (events[]) y evento único
const eventos = body.events || [{ type: body.type, data: body.data }];

return eventos
  .filter(e => e && e.data && e.data.subscriber)
  .map(evento => ({
    json: {
      tipo_evento:   evento.type || '',
      email:         evento.data.subscriber.email || '',
      nombre:        evento.data.subscriber.fields?.name || '',
      apellido:      evento.data.subscriber.fields?.last_name || '',
      subscriber_id: evento.data.subscriber.id || '',
      campaign_id:   evento.data.campaign?.id || '',
      campaign_name: evento.data.campaign?.name || '',
      link_url:      evento.data.link?.url || '',
    }
  }));

// ════════════════════════════════════════════════════════════════
// MAPA DE SERVICIOS: Nombre Campaña MailerLite → Apollo Sequence ID
// ════════════════════════════════════════════════════════════════
// El nombre de la campaña puede ser exacto o una palabra clave.
// El Sequence ID está en la URL de Apollo: /sequences/XXXX
// ════════════════════════════════════════════════════════════════
const SEQUENCE_MAP = {
  // "Nombre campaña MailerLite": "Apollo_Sequence_ID",
  "Servicio A": "APOLLO_SEQUENCE_ID_SERVICIO_A",
  "Servicio B": "APOLLO_SEQUENCE_ID_SERVICIO_B",
  "Servicio C": "APOLLO_SEQUENCE_ID_SERVICIO_C",
  // Agrega más servicios aquí...
};

// ID de la cuenta de email desde la que Apollo envía las secuencias
// Apollo → Settings → Email Accounts → copiar el ID
const APOLLO_EMAIL_ACCOUNT_ID = "TU_APOLLO_EMAIL_ACCOUNT_ID";

const evento = $input.first().json;
const campaignName = evento.campaign_name || '';

// Buscar match exacto primero
let sequenceId = SEQUENCE_MAP[campaignName] || null;

// Si no hay match exacto, buscar por palabra clave
if (!sequenceId) {
  for (const [keyword, seqId] of Object.entries(SEQUENCE_MAP)) {
    if (campaignName.toLowerCase().includes(keyword.toLowerCase())) {
      sequenceId = seqId;
      break;
    }
  }
}

return [{
  json: {
    ...evento,
    sequence_id:         sequenceId,
    email_account_id:    APOLLO_EMAIL_ACCOUNT_ID,
    tiene_secuencia:     sequenceId !== null,
    campaign_name_clean: campaignName,
  }
}];

// people/match devuelve { person: {...} } o { person: null }
const matchResult = $input.first().json;
const eventoData  = $('Mapear Campaña → Secuencia Apollo').item.json;

let apolloContactId = null;
let contactExists   = false;

if (matchResult.person?.id) {
  apolloContactId = matchResult.person.id;
  contactExists   = true;
} else if (matchResult.contacts?.[0]?.id) {
  apolloContactId = matchResult.contacts[0].id;
  contactExists   = true;
}

return [{
  json: {
    ...eventoData,
    apollo_contact_id: apolloContactId,
    contact_exists:    contactExists,
  }
}];

const created  = $input.first().json;
const prevData = $('Verificar si Existe Contacto').item.json;

const newId = created.contact?.id || created.id || null;

return [{
  json: {
    ...prevData,
    apollo_contact_id: newId,
    contact_exists:    true,
  }
}];
